import{_ as e}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{o,c as i,af as n}from"./chunks/runtime-core.esm-bundler.B2oc1Rjn.js";const f=JSON.parse('{"title":"Немного конфликтологии","description":"","frontmatter":{"title":"Немного конфликтологии","date":"2020-09-17T00:00:00.000Z","head":[["link",{"rel":"canonical","href":"https://alterfo.github.io/posts/2020-09-17-conflict-management"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"Немного конфликтологии"}],["meta",{"property":"og:description","content":"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки."}],["meta",{"property":"og:url","content":"https://alterfo.github.io/posts/2020-09-17-conflict-management"}],["meta",{"property":"og:image","content":"https://alterfo.github.io/og.png"}],["meta",{"property":"og:site_name","content":"Alterfo"}],["meta",{"property":"og:locale","content":"ru_RU"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Немного конфликтологии"}],["meta",{"name":"twitter:description","content":"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки."}],["meta",{"name":"twitter:image","content":"https://alterfo.github.io/og.png"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BlogPosting\\",\\"headline\\":\\"Немного конфликтологии\\",\\"description\\":\\"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки.\\",\\"url\\":\\"https://alterfo.github.io/posts/2020-09-17-conflict-management\\",\\"inLanguage\\":\\"ru-RU\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Oleg Sidorkin\\",\\"alternateName\\":\\"alterfo\\",\\"url\\":\\"https://alterfo.github.io\\",\\"jobTitle\\":\\"Software Engineer\\",\\"knowsAbout\\":[\\"Music\\",\\"Audio DSP\\",\\"AI\\",\\"RAG\\",\\"Frontend Development\\",\\"Solution Architecture\\"],\\"sameAs\\":[\\"https://github.com/alterfo\\"]},\\"datePublished\\":\\"2020-09-17\\"}"]]},"headers":[],"relativePath":"posts/2020-09-17-conflict-management.md","filePath":"posts/2020-09-17-conflict-management.md"}'),a={name:"posts/2020-09-17-conflict-management.md"};function l(p,t,r,c,s,m){return o(),i("div",null,[...t[0]||(t[0]=[n("<p>В конфликты попадают так или иначе все, но все мы по-разному из них выходим.</p><p>Под конфликтом я понимаю состояние ситуации, когда есть два субъекта и есть их отношение по поводу какого-либо объекта, приправленное негативными эмоциями друг к другу с обеих сторон. Ссора от конфликта отличается отсутствием объекта. Кроме межличностного конфликт также бывает внутриличностным, суть та же.</p><p>Можно выделить несколько путей выхода из конфликта</p><ul><li>избегание,</li><li>пассивный,</li><li>агрессивный,</li><li>компромисс,</li><li>сотрудничество.</li></ul><p>Оптимальным считается выход на сотрудничество, но мало кто объясняет как это сделать, мол, разбирайтесь сами, вот вам апельсин.</p><p>Похожий на правду ответ я нашёл для себя в книге Даниеля Шапиро &quot;Negotiating Nonnegotiable&quot;. Чтобы &quot;излечить&quot; конфликт, он говорит, нужно смотреть на &quot;трансцедентальную общность&quot;, на что-то что объединяет всё сущее, это поможет подняться над своим эго и племенной идентичностью, и создать контакт с другим человеком. Если вас задевают слова или поступки другого человека, перепалка кажется иногда единственным вариантом отстоять свою идентичность. Ваш оппонент думает так же.</p><p>Ещё мне нравится концепция территорий. Они могут быть не только физическими - например, заняли ваш стул или место на паркове, чем вызвали бурный негатив, но и ментальными - вас оскорбили прилюдно, а с вами так нельзя, вы и покалечить случайно можете.</p><p>Чтобы избегать подобных ситуаций, можно, конечно, накачаться, ходить на тренировки по боевым искусствам, но это тоже не спасает от неадекватных людей.</p><p>Как вариант, имеет смысл завести привычку на каждый контакт ставить цель, не жёстко, конечно, по ходу контакта всё может измениться, но в целом, иметь цель на каждую коммуникацию желательно.</p><p>Хорошая цель коммуникации:</p><ul><li>экологична (win-win),</li><li>измерима и доказуема,</li><li>достижима участниками,</li><li>выражена позитивным языком (без &quot;не&quot; и &quot;без&quot;),</li><li>ранжирована (не меньше чем, но и не больше чем, где-то между)</li></ul><p>Типы целей могут быть:</p><ul><li>получение информации</li><li>изменение эмоционального состояния</li><li>принятие решения</li><li>действие</li></ul><p>Внутриличностные конфликты (неврозы) можно решать точно так же. Поставить на стол две куклы-фигуры, положить между ними объект конфликта и, целенаправленно, вербализировать внутренний диалог.</p><p>Звучит странно, выглядит тоже, но это бездонный источник лулзов и открытий.</p>",15)])])}const d=e(a,[["render",l]]);export{f as __pageData,d as default};
